#!/usr/bin/env python3
# train_model.py — balanced U-Net training on filled masks (Apple M1 friendly)

#!/usr/bin/env python3
# train_model.py — robust, laptop-friendly training on FILLED masks (Apple M1 / CPU)


from __future__ import annotations
import argparse
from pathlib import Path
from typing import List, Tuple, Iterator
import math
import numpy as np
import pandas as pd
import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader, Sampler

DEFAULT_DATA_DIR = "/Users/radish/Desktop/Tsinghua/HI Bubble Detection/patches_256s192"

# ---------------- Dataset ----------------
class TileDataset(Dataset):
    """Loads .npz tiles saved by data_processing.py. target ∈ {mask, region, rim}."""
    def __init__(self, files: List[Path], target: str = "mask"):
        self.files = files
        self.target = target

    def __len__(self) -> int:
        return len(self.files)

    def __getitem__(self, idx: int):
        p = self.files[idx]
        with np.load(p, allow_pickle=True) as z:
            img = z["image"].astype(np.float32)
            if self.target == "rim" and "rim" in z.files:
                m = z["rim"].astype(np.float32)
            else:
                key = "mask" if "mask" in z.files else ("region" if "region" in z.files else "rim")
                m = z[key].astype(np.float32)
        # robust per-tile normalize
        med = np.median(img)
        q25, q75 = np.percentile(img, [25, 75]); iqr = max(q75 - q25, 1e-6)
        img = (img - med) / iqr
        img = img[None, ...]  # C,H,W
        m = m[None, ...]
        return torch.from_numpy(img), torch.from_numpy(m)

# ---------------- Balanced sampler (50% pos / 50% neg per batch) ----------------
class BalancedBatchSampler(Sampler[List[int]]):
    def __init__(self, train_files: List[Path], labels: List[int], batch_size: int, pos_frac: float = 0.5, seed: int = 0):
        assert len(train_files) == len(labels)
        self.pos_idx = [i for i,l in enumerate(labels) if l == 1]
        self.neg_idx = [i for i,l in enumerate(labels) if l == 0]
        self.batch_size = batch_size
        self.k_pos = max(1, int(round(batch_size * pos_frac)))
        self.k_neg = batch_size - self.k_pos
        self.rng = np.random.default_rng(seed)
        # number of batches per epoch (with replacement sampling)
        base = max(len(self.pos_idx) / max(1, self.k_pos), len(self.neg_idx) / max(1, self.k_neg))
        self.num_batches = max(1, math.ceil(base))

    def __iter__(self) -> Iterator[List[int]]:
        for _ in range(self.num_batches):
            pos = self.rng.choice(self.pos_idx, size=self.k_pos, replace=True).tolist() if self.k_pos>0 else []
            neg = self.rng.choice(self.neg_idx, size=self.k_neg, replace=True).tolist() if self.k_neg>0 else []
            yield pos + neg

    def __len__(self) -> int:
        return self.num_batches

# ---------------- Model (GroupNorm for small batches) ----------------
def GN(ch: int) -> nn.GroupNorm:
    for g in (8, 4, 2, 1):
        if ch % g == 0:
            return nn.GroupNorm(g, ch)
    return nn.GroupNorm(1, ch)

class DoubleConv(nn.Module):
    def __init__(self, in_ch: int, out_ch: int):
        super().__init__()
        self.net = nn.Sequential(
            nn.Conv2d(in_ch, out_ch, 3, padding=1), GN(out_ch), nn.ReLU(inplace=True),
            nn.Conv2d(out_ch, out_ch, 3, padding=1), GN(out_ch), nn.ReLU(inplace=True),
        )
    def forward(self, x): return self.net(x)

class UNet(nn.Module):
    def __init__(self, in_channels: int = 1, base_channels: int = 24):
        super().__init__()
        self.enc1 = DoubleConv(in_channels, base_channels); self.pool1 = nn.MaxPool2d(2)
        self.enc2 = DoubleConv(base_channels, base_channels*2); self.pool2 = nn.MaxPool2d(2)
        self.enc3 = DoubleConv(base_channels*2, base_channels*4); self.pool3 = nn.MaxPool2d(2)
        self.bottleneck = DoubleConv(base_channels*4, base_channels*8)
        self.up3 = nn.ConvTranspose2d(base_channels*8, base_channels*4, 2, 2); self.dec3 = DoubleConv(base_channels*8, base_channels*4)
        self.up2 = nn.ConvTranspose2d(base_channels*4, base_channels*2, 2, 2); self.dec2 = DoubleConv(base_channels*4, base_channels*2)
        self.up1 = nn.ConvTranspose2d(base_channels*2, base_channels, 2, 2);  self.dec1 = DoubleConv(base_channels*2, base_channels)
        self.final = nn.Conv2d(base_channels, 1, 1)
    def forward(self, x):
        x1 = self.enc1(x)
        x2 = self.enc2(self.pool1(x1))
        x3 = self.enc3(self.pool2(x2))
        x4 = self.bottleneck(self.pool3(x3))
        x  = self.up3(x4); x = torch.cat([x, x3], 1); x = self.dec3(x)
        x  = self.up2(x);  x = torch.cat([x, x2], 1); x = self.dec2(x)
        x  = self.up1(x);  x = torch.cat([x, x1], 1); x = self.dec1(x)
        return self.final(x)

# ---------------- Loss / metrics ----------------
def dice_loss(logits, target, smooth=1.0):
    prob = torch.sigmoid(logits)
    prob_f = prob.view(prob.size(0), -1)
    tgt_f  = target.view(target.size(0), -1)
    inter  = (prob_f * tgt_f).sum(1)
    denom  = prob_f.sum(1) + tgt_f.sum(1)
    dice = (2*inter + smooth) / (denom + smooth)
    return 1.0 - dice.mean()

def batch_metrics(logits, target, thr=0.2):
    with torch.no_grad():
        prob = torch.sigmoid(logits)
        pred = (prob > thr).float()
        tp = (pred * target).sum().item()
        fp = (pred * (1 - target)).sum().item()
        fn = ((1 - pred) * target).sum().item()
        prec = tp / (tp + fp + 1e-8)
        rec  = tp / (tp + fn + 1e-8)
        f1   = 2*prec*rec / (prec + rec + 1e-8)
    return prec, rec, f1

# ---------------- Split helpers ----------------
def autodetect_device(arg: str) -> str:
    if arg != "auto": return arg
    if torch.backends.mps.is_available(): return "mps"
    if torch.cuda.is_available(): return "cuda"
    return "cpu"

def stratified_files_and_labels(data_dir: Path, val_split: float) -> Tuple[List[Path], List[Path], List[int], List[int]]:
    files = sorted(data_dir.glob("*.npz"))
    if not files:
        raise FileNotFoundError(f"No .npz tiles in {data_dir}")
    idx_path = data_dir / "index.csv"
    if not idx_path.exists():
        rng = np.random.default_rng(0); perm = rng.permutation(len(files))
        cut = int(len(files)*(1.0 - val_split))
        # assume unknown labels → treat all negatives for sampler (we’ll fallback to shuffle)
        return [files[i] for i in perm[:cut]], [files[i] for i in perm[cut:]], [0]*cut, [0]*(len(files)-cut)
    df = pd.read_csv(idx_path)
    name_to_label = {Path(p).name: int(h) for p,h in zip(df["path"], df["has_pos"])}
    pos = [p for p in files if name_to_label.get(p.name, 0) == 1]
    neg = [p for p in files if name_to_label.get(p.name, 0) == 0]
    rng = np.random.default_rng(0); rng.shuffle(pos); rng.shuffle(neg)
    npos_val = max(1, int(len(pos)*val_split)); nneg_val = max(1, int(len(neg)*val_split))
    pos_val, pos_tr = pos[:npos_val], pos[npos_val:]
    neg_val, neg_tr = neg[:nneg_val], neg[nneg_val:]
    train_files = pos_tr + neg_tr; val_files = pos_val + neg_val
    rng.shuffle(train_files); rng.shuffle(val_files)
    # labels aligned to lists
    name_to_label_default0 = lambda p: name_to_label.get(p.name, 0)
    train_labels = [name_to_label_default0(p) for p in train_files]
    val_labels   = [name_to_label_default0(p) for p in val_files]
    print(f"[SPLIT] train: pos={sum(train_labels)} neg={len(train_labels)-sum(train_labels)} | val: pos={sum(val_labels)} neg={len(val_labels)-sum(val_labels)}")
    return train_files, val_files, train_labels, val_labels

# ---------------- Train ----------------
def train_loop(model, train_loader, val_loader, epochs, lr, wd, device, metric_thr, pos_weight):
    model.to(device)
    opt = optim.Adam(model.parameters(), lr=lr, weight_decay=wd)
    best_dice, best = 0.0, None

    for ep in range(1, epochs+1):
        model.train()
        tl = 0.0
        for x,y in train_loader:
            x,y = x.to(device), y.to(device)
            opt.zero_grad()
            out = model(x)
            bce = F.binary_cross_entropy_with_logits(out, y, pos_weight=torch.tensor(pos_weight, device=out.device))
            loss = 0.6*bce + 0.4*dice_loss(out, y)
            loss.backward()
            torch.nn.utils.clip_grad_norm_(model.parameters(), 5.0)
            opt.step()
            tl += loss.item()*x.size(0)
        tl /= len(train_loader.dataset)*1.0  # approximate when using custom sampler

        model.eval()
        vl = 0.0; dsum = 0.0; msum = np.zeros(3); pfrac = 0.0; N = 0
        with torch.no_grad():
            for x,y in val_loader:
                x,y = x.to(device), y.to(device)
                out = model(x)
                bce = F.binary_cross_entropy_with_logits(out, y, pos_weight=torch.tensor(pos_weight, device=out.device))
                val_loss = 0.6*bce + 0.4*dice_loss(out, y)
                bs = x.size(0); vl += val_loss.item() * bs; dsum += (1.0 - dice_loss(out, y).item()) * bs
                prec, rec, f1 = batch_metrics(out, y, thr=metric_thr); msum += np.array([prec, rec, f1]) * bs
                pfrac += y.mean().item() * bs; N += bs
        vl = vl / max(1,N); dice = dsum / max(1,N); prec, rec, f1 = (msum / max(1,N)); pfrac /= max(1,N)
        print(f"Epoch {ep:02d} | train {tl:.4f} | val {vl:.4f} | dice {dice:.4f} | P {prec:.3f} R {rec:.3f} F1 {f1:.3f} | val_pos_frac {pfrac:.5f}")

        if dice > best_dice:
            best_dice, best = dice, {k: v.cpu().clone() for k,v in model.state_dict().items()}

    if best is not None:
        model.load_state_dict(best)
    return model

# ---------------- Main ----------------
def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--data_dir", default=DEFAULT_DATA_DIR)
    ap.add_argument("--val_split", type=float, default=0.2)
    ap.add_argument("--epochs", type=int, default=16)
    ap.add_argument("--batch_size", type=int, default=4)
    ap.add_argument("--learning_rate", type=float, default=1e-3)  # higher LR to escape zero solution
    ap.add_argument("--weight_decay", type=float, default=0.0)
    ap.add_argument("--base_channels", type=int, default=24)
    ap.add_argument("--target", choices=["mask","region","rim"], default="mask")
    ap.add_argument("--device", choices=["auto","cpu","cuda","mps"], default="auto")
    ap.add_argument("--metric_threshold", type=float, default=0.2)
    ap.add_argument("--pos_weight", type=float, default=5.0, help="fixed BCE pos_weight")
    ap.add_argument("--pos_frac_in_batch", type=float, default=0.5, help="target positive fraction per batch")
    args = ap.parse_args()

    device = autodetect_device(args.device)
    torch.set_num_threads(4)
    print(f"[INFO] device = {device}")

    data_dir = Path(args.data_dir)
    train_files, val_files, train_labels, val_labels = stratified_files_and_labels(data_dir, args.val_split)

    train_ds = TileDataset(train_files, target=args.target)
    val_ds   = TileDataset(val_files,   target=args.target)

    # Balanced batches (uses replacement; epoch length = ~max(pos/half, neg/half))
    sampler = BalancedBatchSampler(train_files, train_labels, batch_size=args.batch_size, pos_frac=args.pos_frac_in_batch, seed=0)
    train_ld = DataLoader(train_ds, batch_sampler=sampler, num_workers=0)
    val_ld   = DataLoader(val_ds,   batch_size=args.batch_size, shuffle=False, num_workers=0)

    model = UNet(in_channels=1, base_channels=args.base_channels)

    # small prior to avoid dead negatives
    with torch.no_grad():
        prior = 0.05
        model.final.bias.fill_(float(np.log(prior/(1.0-prior))))

    model = train_loop(model, train_ld, val_ld, args.epochs, args.learning_rate, args.weight_decay, device, args.metric_threshold, args.pos_weight)

    out = Path("model_best.pth")
    torch.save(model.state_dict(), out)
    print(f"[OK] saved → {out}")

if __name__ == "__main__":
    main()